#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct TreeNode {
    int val;
    struct TreeNode* left;
    struct TreeNode* right;
} TreeNode;

// Function to create a new tree node
TreeNode* createTreeNode(int val) {
    TreeNode* newNode = (TreeNode*) malloc(sizeof(TreeNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to find the inorder predecessor and successor
void findPredecessorAndSuccessor(TreeNode* root, TreeNode* p, TreeNode** predecessor, TreeNode** successor) {
    // Initialize predecessor and successor
    *predecessor = NULL;
    *successor = NULL;

    // Perform inorder traversal
    TreeNode* current = root;
    TreeNode* prev = NULL;
    while (current) {
        if (current->val < p->val) {
            prev = current;
            current = current->right;
        } else if (current->val > p->val) {
            if (!*predecessor) {
                *predecessor = prev;
            }
            current = current->left;
        } else {
            // Found the node
            if (current->left) {
                *predecessor = current->left;
                while ((*predecessor)->right) {
                    *predecessor = (*predecessor)->right;
                }
            }
            if (current->right) {
                *successor = current->right;
                while ((*successor)->left) {
                    *successor = (*successor)->left;
                }
            }
            break;
        }
    }
}

int main() {
    // Create the binary search tree
    TreeNode* root = createTreeNode(5);
    root->left = createTreeNode(3);
    root->right = createTreeNode(7);
    root->left->left = createTreeNode(2);
    root->left->right = createTreeNode(4);

    // Find the inorder predecessor and successor
    TreeNode* p = root->left;
    TreeNode* predecessor = NULL;
    TreeNode* successor = NULL;
    findPredecessorAndSuccessor(root, p, &predecessor, &successor);

    // Print the results
