import java.util.*;

// Define the structure for a tree node
public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

public class Solution {
    // Function to find the inorder predecessor and successor
    public void findPredecessorAndSuccessor(TreeNode root, TreeNode p, TreeNode[] predecessor, TreeNode[] successor) {
        // Initialize predecessor and successor
        predecessor[0] = null;
        successor[0] = null;

        // Perform inorder traversal
        TreeNode current = root;
        TreeNode prev = null;
        while (current != null) {
            if (current.val < p.val) {
                prev = current;
                current = current.right;
            } else if (current.val > p.val) {
                if (predecessor[0] == null) {
                    predecessor[0] = prev;
                }
                current = current.left;
            } else {
                // Found the node
                if (current.left != null) {
                    predecessor[0] = current.left;
                    while (predecessor[0].right != null) {
                        predecessor[0] = predecessor[0].right;
                    }
                }
                if (current.right != null) {
                    successor[0] = current.right;
                    while (successor[0].left != null) {
                        successor[0] = successor[0].left;
                    }
                }
                break;
            }
        }
    }

    public static void main(String[] args) {
        // Create the binary search tree
        TreeNode root = new TreeNode(5);
        root.left = new TreeNode(3);
        root.right = new TreeNode(7);
        root.left.left = new TreeNode(2);
        root.left.right = new TreeNode(4);

        // Find the inorder predecessor and successor
        TreeNode p = root.left;
        TreeNode[] predecessor = new TreeNode[1];
        TreeNode[] successor = new TreeNode[1];
        Solution solution = new Solution();
        solution.findPredecessorAndSuccessor(root, p, predecessor, successor);

        // Print the results
        if (predecessor[0] != null) {
            System.out.println("Predecessor: " + predecessor[0].val);
        } else {
            System.out.println("Predecessor: NULL");
        }
        if (successor[0] != null) {
            System.out.println("Successor: " + successor[0].val);
        } else {
            System.out.println("Successor: NULL");
        }
    }
}

